import type { SeriesName } from '../../../types.js';

/**
 * Formats a SeriesName for consistent display across tooltip components.
 * Converts string arrays to a dot-separated string, returns strings as-is.
 */
export const formatSeriesNameForDisplay = (name: SeriesName): string => {
  return Array.isArray(name) ? name.join(' • ') : name || '';
};
